import React, { useState } from 'react';

const Login = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [showPassword, setShowPassword] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (username === 'admin' && password === 'admin@123') {
      onLogin();
      setError('');
    } else {
      setError('Invalid credentials. Username: admin, Password: admin@123');
    }
  };

  const handleForgotPassword = () => {
    alert('Contact administrator for password reset. Demo: admin / admin@123');
  };

  const handleRegister = () => {
    alert('Admin registration disabled. Use default: admin / admin@123');
  };

  return (
    <div className="min-vh-100 d-flex align-items-center justify-content-center bg-gradient" style={{background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'}}>
      <div className="row justify-content-center">
        <div className="col-md-5 col-lg-4">
          <div className="card border-0 shadow-lg login-box animate__animated animate__fadeInUp" style={{backdropFilter: 'blur(20px)', background: 'rgba(255,255,255,0.1)', borderRadius: '20px'}}>
            <div className="card-body p-5">
              <div className="text-center mb-5">
                <i className="fab fa-github fa-3x text-white mb-3"></i>
                <h2 className="text-white mb-1">GitHub Analyzer</h2>
                <p className="text-white-50 mb-0">Admin Login</p>
              </div>
              <form onSubmit={handleSubmit}>
                <div className="mb-4">
                  <label className="form-label text-white">Username</label>
                  <div className="input-group input-group-lg">
                    <span className="input-group-text bg-transparent border-0 text-white"><i className="fas fa-user"></i></span>
                    <input
                      type="text"
                      className="form-control bg-transparent border-0 text-white"
                      placeholder="admin"
                      value={username}
                      onChange={(e) => setUsername(e.target.value)}
                      required
                    />
                  </div>
                </div>
                <div className="mb-4">
                  <label className="form-label text-white">Password</label>
                  <div className="input-group input-group-lg">
                    <span className="input-group-text bg-transparent border-0 text-white"><i className="fas fa-lock"></i></span>
                    <input
                      type={showPassword ? 'text' : 'password'}
                      className="form-control bg-transparent border-0 text-white"
                      placeholder="admin@123"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      required
                    />
                    <button className="btn btn-outline-light btn-sm" type="button" onClick={() => setShowPassword(!showPassword)}>
                      <i className={`fas fa-eye${showPassword ? '-slash' : ''}`}></i>
                    </button>
                  </div>
                </div>
                {error && <div className="alert alert-danger">{error}</div>}
                <button type="submit" className="btn btn-lg btn-primary w-100 mb-3 shadow">
                  <i className="fas fa-sign-in-alt me-2"></i>Login
                </button>
              </form>
              <div className="d-grid gap-2">
                <button className="btn btn-outline-light btn-sm" onClick={handleForgotPassword}>
                  Forgot Password?
                </button>
                <button className="btn btn-outline-light btn-sm" onClick={handleRegister}>
                  Create Account
                </button>
              </div>
              <div className="text-center mt-4">
                <small className="text-white-50">
                  Demo Credentials: <strong>admin / admin@123</strong>
                </small>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
